{
  "script": [
    {
      "speaker": "Sienna",
      "action": "Standing in a brightly lit modern gym. She’s a bit breathless, adjusting her high ponytail, and holds her pastel Stanley cup in one hand.",
      "dialogue": "Alright team, quick reality check: **Sweat, squat, conquer. Sienna's gym essentials just leveled up.**"
    },
    {
      "speaker": "Sienna",
      "action": "Looking directly at the camera, her tone energetic and authentic, gesturing to her seamless sage green leggings.",
      "dialogue": "You know when your workout demands everything, your gear should too. These Seamless Sage Green Leggings? *[Pulls at the fabric, showing the seamless detail.]* They're built for undeniable comfort and unwavering confidence – seriously."
    },
    {
      "speaker": "Sienna",
      "action": "Performs a deep, controlled squat, demonstrating the flexibility and form of the leggings. She smiles confidently.",
      "dialogue": "Go squat-deep, go strong. Because like I always say, 'Your body can stand almost anything. It’s your mind that you have to convince.'"
    },
    {
      "speaker": "Sienna",
      "action": "Stands up, takes a casual sip from her massive pastel Stanley cup, and subtly wipes a small amount of sweat from her forehead.",
      "dialogue": "So, if you're ready to train without limits, you absolutely have to check out the Arrowow Active Seamless Collection. It's a total game-changer for your training."
    }
  ]
}
